""";

var outputDir = "dist";
var includeTests = true;
var includeTargets = true;

for (var index = 0; index < args.Length; index++)
{
    switch (args[index])
    {
        case "--skip-tests":
            includeTests = false;
            break;
        case "--skip-targets":
            includeTargets = false;
            break;
        case "--help":
        case "-h":
            PrintUsage();
            return;
        default:
            if (args[index].StartsWith("--", StringComparison.Ordinal))
            {
                throw new ArgumentException($"Unknown argument: {args[index]}");
            }

            outputDir = args[index];
            break;
    }
}

Directory.CreateDirectory(outputDir);
WriteEmbeddedFile(Path.Combine(outputDir, "SqlTestSupport.cs"), RuntimeBundleBase64);
if (includeTests)
{
    WriteEmbeddedFile(Path.Combine(outputDir, "SqlTestSupport.Tests.cs"), TestBundleBase64);
}

if (includeTargets)
{
    WriteTargets(Path.Combine(outputDir, "SqlTestSupport.Directory.Build.targets"));
}

static void PrintUsage()
{
    Console.WriteLine("Usage: dotnet run -- [output-dir] [--skip-tests] [--skip-targets]");
}

static void WriteEmbeddedFile(string path, string base64Content)
{
    var directory = Path.GetDirectoryName(path);
    if (!string.IsNullOrEmpty(directory))
    {
        Directory.CreateDirectory(directory);
    }

    File.WriteAllText(
        path,
        Encoding.UTF8.GetString(Convert.FromBase64String(base64Content)),
        new UTF8Encoding(encoderShouldEmitUTF8Identifier: false));
    Console.WriteLine($"Wrote {path}");
}

static void WriteTargets(string path)
{
    var target = new StringBuilder();
    target.AppendLine("<?xml version=\"1.0\" encoding=\"utf-8\"?>");
    target.AppendLine("<Project>");
    target.AppendLine("  <!-- SqlTestSupport self-contained MSBuild bootstrap. Copy this file as Directory.Build.targets next to the destination test project and build. -->");
    target.AppendLine("  <PropertyGroup>");
    target.AppendLine("    <SqlTestSupportExpandOnBuild Condition=\"'$(SqlTestSupportExpandOnBuild)' == ''\">true</SqlTestSupportExpandOnBuild>");
    target.AppendLine("    <SqlTestSupportIncludeSelfTests Condition=\"'$(SqlTestSupportIncludeSelfTests)' == ''\">false</SqlTestSupportIncludeSelfTests>");
    target.AppendLine("    <SqlTestSupportAddPackageReferences Condition=\"'$(SqlTestSupportAddPackageReferences)' == ''\">true</SqlTestSupportAddPackageReferences>");
    target.AppendLine("  </PropertyGroup>");
    target.AppendLine("  <ItemGroup Condition=\"'$(SqlTestSupportAddPackageReferences)' == 'true'\">");
    target.AppendLine("    <PackageReference Include=\"Microsoft.SqlServer.TransactSql.ScriptDom\" Version=\"180.18.1\" Condition=\"'@(PackageReference->WithMetadataValue('Identity', 'Microsoft.SqlServer.TransactSql.ScriptDom'))' == ''\" />");
    target.AppendLine("    <PackageReference Include=\"MSTest.TestFramework\" Version=\"4.0.2\" Condition=\"'@(PackageReference->WithMetadataValue('Identity', 'MSTest.TestFramework'))' == ''\" />");
    target.AppendLine("  </ItemGroup>");
    target.AppendLine("  <UsingTask TaskName=\"SqlTestSupportWriteEmbeddedFile\" TaskFactory=\"RoslynCodeTaskFactory\" AssemblyFile=\"$(MSBuildToolsPath)\\Microsoft.Build.Tasks.Core.dll\">");
    target.AppendLine("    <ParameterGroup><OutputPath ParameterType=\"System.String\" Required=\"true\" /><Base64Content ParameterType=\"System.String\" Required=\"true\" /></ParameterGroup>");
    target.AppendLine("    <Task><Using Namespace=\"System\" /><Using Namespace=\"System.IO\" /><Using Namespace=\"System.Text\" /><Code Type=\"Fragment\" Language=\"cs\"><![CDATA[");
    target.AppendLine("var directory = Path.GetDirectoryName(OutputPath);");
    target.AppendLine("if (!string.IsNullOrEmpty(directory)) { Directory.CreateDirectory(directory); }");
    target.AppendLine("File.WriteAllText(OutputPath, Encoding.UTF8.GetString(Convert.FromBase64String(Base64Content)), new UTF8Encoding(encoderShouldEmitUTF8Identifier: false));");
    target.AppendLine("      ]]></Code></Task>");
    target.AppendLine("  </UsingTask>");
    target.AppendLine("  <PropertyGroup>");
    target.AppendLine("    <SqlTestSupportRuntimeBundleBase64>");
    target.AppendLine(RuntimeBundleBase64);
    target.AppendLine("    </SqlTestSupportRuntimeBundleBase64>");
    target.AppendLine("    <SqlTestSupportTestBundleBase64>");
    target.AppendLine(TestBundleBase64);
    target.AppendLine("    </SqlTestSupportTestBundleBase64>");
    target.AppendLine("  </PropertyGroup>");
    target.AppendLine("  <Target Name=\"SqlTestSupportExpandEmbeddedSources\" BeforeTargets=\"CoreCompile\" Condition=\"'$(SqlTestSupportExpandOnBuild)' == 'true'\">");
    target.AppendLine("    <PropertyGroup><SqlTestSupportExpandedSourceDir>$(IntermediateOutputPath)SqlTestSupport\\</SqlTestSupportExpandedSourceDir><SqlTestSupportExpandedRuntimeSource>$(SqlTestSupportExpandedSourceDir)SqlTestSupport.cs</SqlTestSupportExpandedRuntimeSource><SqlTestSupportExpandedTestSource>$(SqlTestSupportExpandedSourceDir)SqlTestSupport.Tests.cs</SqlTestSupportExpandedTestSource></PropertyGroup>");
    target.AppendLine("    <SqlTestSupportWriteEmbeddedFile OutputPath=\"$(SqlTestSupportExpandedRuntimeSource)\" Base64Content=\"$(SqlTestSupportRuntimeBundleBase64)\" />");
    target.AppendLine("    <SqlTestSupportWriteEmbeddedFile Condition=\"'$(SqlTestSupportIncludeSelfTests)' == 'true'\" OutputPath=\"$(SqlTestSupportExpandedTestSource)\" Base64Content=\"$(SqlTestSupportTestBundleBase64)\" />");
    target.AppendLine("    <ItemGroup><Compile Include=\"$(SqlTestSupportExpandedRuntimeSource)\" Link=\"SqlTestSupport.cs\" /><Compile Include=\"$(SqlTestSupportExpandedTestSource)\" Link=\"SqlTestSupport.Tests.cs\" Condition=\"'$(SqlTestSupportIncludeSelfTests)' == 'true'\" /></ItemGroup>");
    target.AppendLine("  </Target>");
    target.AppendLine("</Project>");
    WriteEmbeddedFile(path, Convert.ToBase64String(Encoding.UTF8.GetBytes(target.ToString())));
}

